def fibonacci(n):
    # Casos borde: n negativo o no entero
    if not isinstance(n, int) or isinstance(n, bool):
        raise TypeError("El argumento debe ser un entero")
    if n < 0:
        raise ValueError("El argumento debe ser mayor o igual a cero")

    # Casos base
    if n == 0:
        return 0
    if n == 1:
        return 1

    # Iterativo para evitar stack overflow en valores grandes
    anterior, actual = 0, 1
    for _ in range(2, n + 1):
        anterior, actual = actual, anterior + actual

    return actual


